INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('higiene_oral', 'Meu bebê tem sapinho na boca, como limpar?', 'Gaze molhada em água morna. Limpa a língua e boca delicadamente. Se não passar, procura o pediatra.', 'higiene_oral', 'higiene_oral', 'higiene_oral', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('higiene_oral', 'Como tratar assadura?', 'Deixa o bebê sem fralda quando possível. Pomada de zinco ajuda. Se não melhorar, procura o pediatra.', 'higiene_oral', 'higiene_oral', 'higiene_oral', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('higiene_oral', 'Quando começam a nascer os dentes?', 'Por volta dos 6 meses! Alguns começam mais cedo, outros mais tarde. Cada bebê é único!', 'higiene_oral', 'higiene_oral', 'higiene_oral', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('higiene_oral', 'Bebê com dente pode morder o peito?', 'Sim! Mas é raro. Se morder, tire o peito e diga não. Ele aprende rápido.', 'higiene_oral', 'higiene_oral', 'higiene_oral', 0, 'true');
INSERT INTO wilborKnowledgeBase (kbCategory, question, keywords, answerPt, answerEn, answerEs, priority, kbIsActive) VALUES ('higiene_oral', 'Como limpar os dentes do bebê?', 'Gaze molhada ou escova macia. Sem pasta de dente antes de 2 anos!', 'higiene_oral', 'higiene_oral', 'higiene_oral', 0, 'true');

